const d = $input.first().json.body || $input.first().json;

const name = d.name || 'Не указано';
const phone = d.phone || 'Не указано';
const niche = d.niche || 'Не указано';
const answers = d.answers || {};
const ts = new Date().toLocaleString('ru-RU', {timeZone: 'Asia/Almaty'});

const waLink = 'wa.me/' + phone.replace(/[^0-9]/g, '');

const lines = [
  '🔥 <b>НОВАЯ ЗАЯВКА С САЙТА DOS</b> 🔥',
  '',
  '👤 <b>Имя:</b> ' + name,
  '📱 <b>Телефон:</b> ' + phone,
  '💼 <b>Ниша:</b> ' + niche,
  '',
  '📋 <b>Ответы на квиз:</b>',
];

const stepNames = [
  'Что автоматизировать',
  'Заявок в месяц',
  'Мессенджеры',
  'Кто обрабатывает заявки',
  'Средний чек',
  'Когда запустить'
];

for (let i = 1; i <= 6; i++) {
  const key = 'step' + i;
  if (answers[key] && answers[key] !== 'не выбрано') {
    lines.push('   ' + stepNames[i-1] + ': <b>' + answers[key] + '</b>');
  }
}

lines.push('');
lines.push('📅 ' + ts);
lines.push('💬 WhatsApp: ' + waLink);

return [{ json: { message: lines.join('\n'), name, phone, niche } }];
